// ‚ĒÄ‚ĒÄ‚ĒÄ Management API ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ
const express   = require('express');
const crypto    = require('crypto');
const mgmt      = express();
const MGMT_PORT = process.env.MGMT_PORT || 9999;
const MGMT_KEY  = process.env.HONEYAI_MGMT_KEY || crypto.randomBytes(32).toString('hex');

// Management API ‚ÄĒ localhost ONLY + API key auth (HIGH-02) + CORS denied (MED-06)
mgmt.use((req, res, next) => {
    const clientIp = req.socket.remoteAddress;
    if (clientIp !== '127.0.0.1' && clientIp !== '::1' && clientIp !== '::ffff:127.0.0.1') {
        return res.status(403).json({ error: 'Forbidden' });
    }
    // Block CORS preflight ‚ÄĒ no cross-origin access ever
    if (req.method === 'OPTIONS') {
        return res.status(403).end();
    }
    res.removeHeader('Access-Control-Allow-Origin');
    
    if (req.path === '/health') {
        return next();
    }

    // Custom cookie parser
    const cookies = {};
    if (req.headers.cookie) {
        req.headers.cookie.split(';').forEach(c => {
            const parts = c.split('=');
            cookies[parts[0].trim()] = parts.slice(1).join('=').trim();
        });
    }

    const key = req.headers['x-api-key'] || req.query.key || cookies['honeyai-key'];
    
    if (key !== MGMT_KEY) {
        return res.status(401).send('Unauthorized');
    }

    // If key came from query parameter, set cookie and redirect to clean URL
    if (req.query.key) {
        res.setHeader('Set-Cookie', `honeyai-key=${MGMT_KEY}; Path=/; HttpOnly; SameSite=Strict`);
        return res.redirect(req.path);
    }

    next();
});

mgmt.disable('x-powered-by');

// Serve static dashboard files
mgmt.use(express.static(path.join(__dirname, 'dashboard')));

mgmt.get('/health', (_, res) => res.json({ status: 'ok', uptime: Math.floor(process.uptime()), pid: process.pid }));

mgmt.get('/stats', (_, res) => {
    const eventsFile = config.logging.events_file;
    let events = [];
    try {
        events = readLastLinesSync(eventsFile, 2000)
            .map(l => { try { return JSON.parse(l); } catch { return null; } })
            .filter(Boolean);
    } catch (_) {}

    const byProto = {};
    const ipSet   = new Set();
    events.forEach(e => {
        byProto[e.protocol] = (byProto[e.protocol] || 0) + 1;
        if (e.ip) ipSet.add(e.ip);
    });

    res.json({
        total_events:   events.length,
        unique_ips:     ipSet.size,
        by_protocol:    byProto,
        last_event:     events[events.length - 1] || null,
        uptime_seconds: Math.floor(process.uptime())
    });
});

mgmt.get('/events', (req, res) => {
    const eventsFile = config.logging.events_file;
    const limit = Math.min(parseInt(req.query.limit) || 50, 500); // cap at 500
    let events = [];
    try {
        events = readLastLinesSync(eventsFile, limit)
            .map(l => { try { return JSON.parse(l); } catch { return null; } })
            .filter(Boolean);
    } catch (_) {}
    res.json(events);
});

// Cache CrowdSec decisions output for 30s to prevent CPU thrashing
let cachedDecisions = null;
let lastDecisionsFetch = 0;

mgmt.get('/sys', async (_, res) => {
    const now = Date.now();

    const fetchDecisions = async () => {
        if (!process.env.CROWDSEC_BOUNCER_KEY) return null;
        try {
            const lapi = process.env.CROWDSEC_LAPI_URL || 'http://127.0.0.1:8080';
            const response = await fetch(`${lapi}/v1/decisions`, {
                headers: { 'X-Api-Key': process.env.CROWDSEC_BOUNCER_KEY }
            });
            if (!response.ok) {
                throw new Error(`CrowdSec LAPI responded with status: ${response.status}`);
            }
            return await response.json();
        } catch (err) {
            return { error: `LAPI fetch failed: ${err.message}` };
        }
    };

    if (!cachedDecisions || (now - lastDecisionsFetch > 30000)) {
        cachedDecisions = await fetchDecisions();
        lastDecisionsFetch = now;
    }

    res.json({
        system: {
            cpu_usage: process.cpuUsage(),
            memory: process.memoryUsage(),
            uptime_seconds: Math.floor(process.uptime()),
            pid: process.pid
        },
        active_connections: global.activeConnections,
        crowdsec_decisions: cachedDecisions
    });
});

mgmt.listen(MGMT_PORT, '127.0.0.1', () => {
    logger.info(`Management API on :${MGMT_PORT} (localhost only, key: ***)`, { protocol: 'core' });
});

// ‚ĒÄ‚ĒÄ‚ĒÄ Process resilience ‚ÄĒ don't crash on unhandled errors ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ
process.on('SIGTERM', () => { logger.info('Shutting down gracefully...'); process.exit(0); });
process.on('SIGINT',  () => { logger.info('Interrupted. Bye!'); process.exit(0); });

// Log but NEVER crash on uncaught exceptions ‚ÄĒ attackers must not be able to kill the honeypot
process.on('uncaughtException', (err) => {
    logger.error(`Uncaught exception (recovering): ${err.message}`);
    // Don't exit ‚ÄĒ honeypot stays alive
});

process.on('unhandledRejection', (reason) => {
    const msg = reason instanceof Error ? reason.message : String(reason);
    logger.warn(`Unhandled promise rejection (recovering): ${msg}`);
    // Don't exit
});
